<template>
    <CommonList
            selection-type="radio"
            row-key="userId"
            :has-more-search="true"
            :auto-load="true"
            ref="listRef"
            cellOverflow="ellipsis"
            @selection-change="handleSelectionChange"
            @current-row-change="handleCurrentRowChange"
            @load-start="handleLoadList"
            @search-click="handleLoadList"
            @pagination-change="handleLoadList"
            @reset-click="handleReset"
    >
        <!-- 固定搜索区 -->
        <template #search-item-fixed>
            <div class="common-search-item">
                <label class="common-search-label80">用户ID：</label>
                <el-input v-model="searchForm.userId" class="common-input120" placeholder="请输入用户ID"></el-input>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">用户名称：</label>
                <el-input v-model="searchForm.userName" class="common-input120" placeholder="请输入用户名称"></el-input>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">用户生效：</label>
                <el-select v-model="searchForm.isDeleted" class="common-input100" placeholder="请选择">
                    <el-option label="是" value="0"></el-option>
                    <el-option label="否" value="1"></el-option>
                </el-select>
            </div>
        </template>

        <!-- 展开搜索区 -->
        <template #search-item-expand>
            <div class="common-search-item">
                <label class="common-search-label80">手机号：</label>
                <el-input v-model="searchForm.phoneNumber" class="common-input120" placeholder="请输入手机号"></el-input>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">邮箱：</label>
                <el-input v-model="searchForm.email" class="common-input120" placeholder="请输入邮箱"></el-input>
            </div>

<!--            <div class="common-search-item">-->
<!--                <label class="common-search-label80">创建时间：</label>-->
<!--                <el-date-picker-->
<!--                        v-model="searchForm.createTime"-->
<!--                        type="date"-->
<!--                        placeholder="请选择创建时间"-->
<!--                        class="common-date150"-->
<!--                ></el-date-picker>-->
<!--            </div>-->
<!--            <div class="common-search-item">-->
<!--                <label class="common-search-label80">更新时间：</label>-->
<!--                <el-date-picker-->
<!--                        v-model="searchForm.updateTimeRange"-->
<!--                        type="datetimerange"-->
<!--                        range-separator="至"-->
<!--                        start-placeholder="开始时间"-->
<!--                        end-placeholder="结束时间"-->
<!--                        format="YYYY-MM-DD"-->
<!--                        value-format="YYYY-MM-DD"-->
<!--                        class="common-date300"-->
<!--                ></el-date-picker>-->
<!--            </div>-->
        </template>

        <!-- 操作按钮 -->
        <template #btn-group>
<!--            <el-button type="primary" class="list-btn" @click="handleAdd">-->
<!--                <el-icon>-->
<!--                    <Plus/>-->
<!--                </el-icon>-->
<!--                新增用户-->
<!--            </el-button>-->
            <el-button
                    type="warning"
                    class="list-btn"
                    @click="handleEdit"
                    :disabled="!selectedRow"
            >
                <el-icon>
                    <Edit/>
                </el-icon>
                修改用户
            </el-button>
            <el-button
                    type="danger"
                    class="list-btn"
                    @click="handleDelete"
                    :disabled="!selectedRow || selectedRow?.value?.isDeleted === 0"
            >
                <el-icon>
                    <Delete/>
                </el-icon>
                删除用户
            </el-button>
        </template>

        <!-- 表格列 width="auto" 占剩余宽度 :resizable="false" 不可拖拽-->
        <template #table-column>
            <el-table-column prop="userId" label="用户ID" align="center" width="120"></el-table-column>
            <el-table-column prop="userName" label="用户名称" align="center" width="180"></el-table-column>
            <el-table-column prop="registrationMethod" label="注册方式" align="center" min-width="120"></el-table-column>
            <el-table-column prop="phoneNumber" label="手机号" align="center" min-width="120"></el-table-column>
            <el-table-column prop="email" label="邮箱" align="center" min-width="160"></el-table-column>
            <el-table-column prop="isDeleted" label="是否生效" align="center" width="100" >
                <template #default="scope">
                    <el-tag :class="scope.row.isDeleted === 0 ? 'list-status-normal' : 'list-status-deleted'">
                        {{ scope.row.isDeleted === 0? '是' : '否' }}
                    </el-tag>
                </template>
            </el-table-column>
            <el-table-column prop="lastLoginTime" label="最后登录时间" align="center" min-width="180"
             :formatter="(row) => $formatTime(row.lastLoginTime)"
            ></el-table-column>

            <el-table-column label="配置角色" align="center" width="100" :resizable="false">
                <template #default="scope">
                    <el-button
                            type="primary"
                            size="small"
                    :disabled="scope.row.isDeleted != '0'"
                    @click="configuration(scope.row)">
                    配置
                    </el-button>
                </template>
            </el-table-column>
        </template>

        <!-- 新增/编辑弹窗 -->
        <template #extra>
            <el-dialog
                    v-model="dialogVisible"
                    :title="dialogType === 'add' ? '新增用户' : '修改用户'"
                    width="800px"
                    destroy-on-close
            >
                <el-form
                        ref="formRef"
                        :model="formData"
                        :rules="formRules"
                        label-width="100px"
                        class="list-modal-form"
                >
                    <el-form-item label="用户ID" prop="userId">
                        <el-input
                                v-model="formData.userId"
                                :disabled= true
                                placeholder="请输入用户ID"
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="用户名称" prop="userName">
                        <el-input
                                v-model="formData.userName"
                                placeholder="请输入用户名称"
                                maxlength="20"
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="手机号" prop="phoneNumber">
                        <el-input
                                v-model="formData.phoneNumber"
                                placeholder="请输入11位有效手机号"
                                maxlength="11"
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="邮箱" prop="email">
                        <el-input
                                v-model="formData.email"
                                placeholder="请输入邮箱地址"
                                maxlength="100"
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="微信">
                        <el-input
                                v-model="formData.wechat"
                                placeholder="暂无微信"
                                disabled
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="是否生效" prop="isDeleted">
                        <el-radio-group v-model="formData.isDeleted">
                            <el-radio :label="0">是</el-radio>
                            <el-radio :label="1">否</el-radio>
                        </el-radio-group>
                    </el-form-item>
                </el-form>
                
                <!-- 公司信息管理 -->
                <div style="margin-top: 20px; border-top: 1px solid #e6e6e6; padding-top: 20px;">
                    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;">
                        <span style="font-weight: bold;">公司信息</span>
                        <el-button type="primary" size="small" @click="handleAddCompany">
                            <el-icon><Plus /></el-icon>
                            添加
                        </el-button>
                    </div>
                    <el-table v-if="formData.companyList && formData.companyList.length" :data="formData.companyList" border style="width: 100%">
                    <el-table-column prop="companyName" label="公司名称" width="180"></el-table-column>
                    <el-table-column prop="companyType" label="公司类型" width="120">
                        <template #default="{ row }">
                            {{ getCompanyTypeName(row.companyType) }}
                        </template>
                    </el-table-column>
                    <el-table-column prop="contactPhone" label="联系电话" width="130"></el-table-column>
                    <el-table-column prop="companyAddress" label="公司地址"></el-table-column>
                    <el-table-column prop="miniProgramCode" label="小程序编码" width="250" show-overflow-tooltip></el-table-column>
                    <el-table-column prop="isMain" label="主公司" width="80">
                        <template #default="{ row }">
                            <el-tag v-if="row.isMain === '1'" type="success">是</el-tag>
                            <el-tag v-else type="info">否</el-tag>
                        </template>
                    </el-table-column>
                    <el-table-column label="操作" width="140">
                        <template #default="{ row, $index }">
                            <el-button type="primary" size="small" @click="handleEditCompany(row, $index)">编辑</el-button>
                            <el-button type="danger" size="small" @click="handleDeleteCompany($index)">删除</el-button>
                        </template>
                    </el-table-column>
                </el-table>
                    <div v-else style="color: #909399;">暂无公司信息</div>
                </div>

                <template #footer>
                    <div style="text-align: center; width: 100%;">
                        <el-button @click="dialogVisible = false">取消</el-button>
                        <el-button type="primary" @click="handleSubmit">确定</el-button>
                    </div>
                </template>
            </el-dialog>

            <!-- 公司编辑弹窗 -->
            <el-dialog v-model="showCompanyDialog" :title="companyDialogTitle" width="500px">
                <el-form :model="companyForm" :rules="companyFormRules" ref="companyFormRef" label-width="100px">
                    <el-form-item label="公司名称" prop="companyName">
                        <el-input v-model="companyForm.companyName" placeholder="请输入公司名称" maxlength="64"></el-input>
                    </el-form-item>
                    <el-form-item label="公司类型" prop="companyType">
                        <el-select v-model="companyForm.companyType" placeholder="请选择公司类型" style="width: 100%;">
                            <el-option v-for="item in companyTypeList" :key="item.code" :label="item.enumCodeName" :value="item.code"></el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item label="联系电话" prop="contactPhone">
                        <el-input v-model="companyForm.contactPhone" placeholder="请输入联系电话"></el-input>
                    </el-form-item>
                    <el-form-item label="公司地址" prop="companyAddress">
                        <el-input v-model="companyForm.companyAddress" placeholder="请输入公司地址" maxlength="200"></el-input>
                    </el-form-item>
                    <el-form-item label="小程序编码">
                        <el-input v-model="companyForm.miniProgramCode" placeholder="请输入小程序编码" clearable></el-input>
                    </el-form-item>
                    <el-form-item label="主公司">
                        <el-switch v-model="companyForm.isMain" active-value="1" inactive-value="0"></el-switch>
                    </el-form-item>
                </el-form>
                <template #footer>
                    <el-button @click="showCompanyDialog = false">取消</el-button>
                    <el-button type="primary" @click="handleSaveCompany">保存</el-button>
                </template>
            </el-dialog>

            <el-dialog
                    v-model="configRoleDialogVisible"
                    title="角色配置"
                    width="600px"
                    destroy-on-close
            >
                <el-tree
                        ref="roleTreeRef"
                        :data="roleTreeData"
                        :props="treeProps"
                        show-checkbox
                        node-key="roleId"
                        :checked-keys="checkedRoleKeys"
                        class="menu-tree"
                ></el-tree>
                <template #footer>
                    <div style="text-align: center; width: 100%;">
                        <el-button @click="configRoleDialogVisible = false">取消</el-button>
                        <el-button type="primary" @click="roleDialogSubmit">提交</el-button>
                    </div>
                </template>
            </el-dialog>
        </template>
    </CommonList>
</template>

<script setup>
    import useRoleList from './userList.js';
    //暴露树组件供js使用 判断树组件渲染完成后再初始化 check
    import { ref } from 'vue';
    const roleTreeRef = ref(null);
    const {
        searchForm,
        listRef,
        dialogVisible,
        dialogType,
        formRef,
        selectedRow,
        formData,
        formRules,
        Plus, Edit, Delete,
        handleSelectionChange,
        handleCurrentRowChange,
        handleEdit,
        handleDelete,
        handleSubmit,
        handleLoadList,
        handleReset,
        configuration,
        configRoleDialogVisible,
        roleTreeData,
        treeProps,
        roleDialogSubmit,
        checkedRoleKeys,
        showCompanyDialog,
        companyDialogTitle,
        companyFormRef,
        companyForm,
        companyFormRules,
        companyTypeList,
        getCompanyTypeName,
        handleAddCompany,
        handleEditCompany,
        handleSaveCompany,
        handleDeleteCompany
    } = useRoleList(roleTreeRef);
</script>

<style>
    @import '../../../assets/css/util/base-list.css';

</style>
<style scoped>
    /* 菜单树样式优化 */
    .menu-tree {
        max-height: 400px;
        overflow-y: auto;
        padding: 10px;
    }
</style>
