import { ref, reactive, onActivated, onMounted, nextTick } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { Plus, Edit, Delete } from '@element-plus/icons-vue'
import { request } from '@/util/globalContext';
import { ValidConst } from '@/util/validConst'
import { getCompanyFormRules } from '../home.js'
import { enumSelect } from '@/util/vueutil/commonList'

// 用户列表逻辑处理
export default function useRoleList(roleTreeRef) {
    // ========== 响应式数据定义 ==========
    // 角色配置弹窗相关
    const configRoleDialogVisible = ref(false) // 菜单配置弹窗显示状态
    const roleTreeData = ref([]) // 角色树数据
    const checkedRoleKeys = ref([]) // 树节点选中的角色ID
    const treeProps = { // 树形结构配置项
        label: 'roleName',  // 角色名称字段
        children: 'children'
    }

    // 搜索表单（默认值初始化）
    const searchForm = reactive({
        userId: '',
        userName: '',
        isDeleted: '',
        createTime: '',
        updateTimeRange: []
    })

    // 列表及弹窗核心响应式数据
    const listRef = ref(null) // 列表组件引用
    const dialogVisible = ref(false) // 新增/编辑弹窗显示状态
    const dialogType = ref('add') // 弹窗类型：add-新增 edit-编辑
    const formRef = ref(null) // 表单组件引用
    const selectedRow = ref(null) // 当前选中的行数据

    // 表单默认值
    const FORM_DEFAULT = {
        userId: '',
        userName: '',
        phoneNumber: '',
        email: '',
        wechat: '',
        isDeleted: 0,
        companyList: []
    }
    const formData = reactive({ ...FORM_DEFAULT }) // 表单绑定数据
    
    // 公司编辑相关
    const showCompanyDialog = ref(false)
    const companyDialogTitle = ref('添加公司')
    const companyFormRef = ref(null)
    const companyTypeList = ref([])
    const companyForm = reactive({
        companyId: '',
        companyName: '',
        contactPhone: '',
        companyAddress: '',
        companyType: '',
        isMain: '0',
        miniProgramCode: ''
    })
    const companyFormRules = reactive(getCompanyFormRules())
    // 记录编辑的公司索引
    const editingCompanyIndex = ref(-1)

    // 表单校验规则
    const formRules = reactive({
        userName: [
            { required: true, message: '请输入用户名称', trigger: 'blur' },
            { max: 20, message: '角色ID长度不能超过25个字符', trigger: 'blur' }
        ],
        phoneNumber: [
            { required: true, message: '请输入11位有效手机号', trigger: 'blur' },
            // 自定义手机号正则校验
            {pattern: ValidConst.PHONE_REG, message: ValidConst.PHONE_MSG,trigger: 'blur'}
        ],
        email: [{ required: true, message: '请输入邮箱地址', trigger: 'blur' },
            {pattern: ValidConst.EMAIL_REG,message: ValidConst.EMAIL_MSG,trigger: 'blur'}
        ],
        roleName: [
            { required: true, message: '请输入角色名称', trigger: 'blur' },
            { max: 25, message: '角色名称长度不能超过25个字符', trigger: 'blur' }
        ],
        isDeleted: [{ required: true, message: '请选择是否生效', trigger: 'change' }],
        roleDesc: [
            { max: 100, message: '角色描述长度不能超过100个字符', trigger: 'blur' }
        ]
    })

    // ========== 核心方法 - 列表加载 ==========
    // 加载角色列表（含分页、搜索参数）
    const handleLoadList = async (paginationParams) => {
        if (!listRef.value) return
        // 校验列表组件初始化状态
        if (!listRef.value.isInited) {
            await nextTick()
            if (!listRef.value.isInited) {
                ElMessage.warning('列表组件初始化中，请稍后重试')
                return
            }
        }

        listRef.value.setLoading(true)
        try {
            // 组装请求参数（分页+搜索+时间范围拆解）
            const params = {
                ...paginationParams,
                ...searchForm,
                updateTimeStart: searchForm.updateTimeRange[0] || '',
                updateTimeEnd: searchForm.updateTimeRange[1] || ''
            }
            const res = await request.get('/user/getUserList', { params })
            if (res.code === 200) {
                // 更新列表数据和分页信息
                listRef.value.updateListData(res.data.records || [])
                listRef.value.updatePagination({
                    pageNum: paginationParams.pageNum,
                    pageSize: paginationParams.pageSize,
                    total: res.data.total || 0
                })
            } else {
                ElMessage.error('列表加载失败：' + (res.msg || '接口异常'))
                listRef.value.updateListData([])
                listRef.value.updatePagination({ ...paginationParams, total: 0 })
            }
        } catch (error) {
            ElMessage.error('列表加载失败：网络异常')
            listRef.value.updateListData([])
            listRef.value.updatePagination({ ...paginationParams, total: 0 })
        } finally {
            listRef.value.setLoading(false)
        }
    }

    // ========== 列表交互 - 行选择 ==========
    // 列表勾选行变化
    const handleSelectionChange = (val) => {
        selectedRow.value = val?.length ? val[0] : null
    }
    // 列表当前行变化
    const handleCurrentRowChange = (val) => {
        selectedRow.value = val
    }

    // ========== 弹窗操作 - 新增/编辑 ==========
    // 新增用户（重置表单+打开弹窗）
    const handleAdd = () => {
        dialogType.value = 'add'
        formRef.value?.resetFields() // 清空表单校验状态
        Object.assign(formData, FORM_DEFAULT) // 重置表单数据
        dialogVisible.value = true
    }

    // 编辑用户（获取选中行详情+打开弹窗）
    const handleEdit = async () => {
        if (!selectedRow.value) {
            ElMessage.warning('请先选中一条数据！')
            return
        }
        if (!listRef.value?.isInited) {
            ElMessage.warning('列表组件初始化中，请稍后重试')
            return
        }

        try {
            listRef.value.setLoading(true)
            // 查询选中用户详情
            const res = await request.get('/user/getUserList', {
                params: { userId: selectedRow.value.userId }
            })

            if (res.code !== 200) {
                ElMessage.error(  res.msg || '接口异常')
                return
            }
            // 赋值表单数据
            const userData = res.data.records[0]
            formData.userId = userData.userId
            formData.userName = userData.userName
            formData.phoneNumber = userData.phoneNumber
            formData.email = userData.email
            formData.isDeleted = userData.isDeleted
            
            // 获取用户公司信息和微信
            try {
                const companyRes = await request.get('/home/getUserDetail', {
                    params: { userId: userData.userId }
                })
                if (companyRes && companyRes.code === 200) {
                    formData.companyList = companyRes.data.companyList || []
                    formData.wechat = companyRes.data.wechat || ''
                } else {
                    formData.companyList = []
                    formData.wechat = ''
                }
            } catch (err) {
                console.error('获取公司信息失败', err)
                formData.companyList = []
                formData.wechat = ''
            }

            dialogType.value = 'edit'
            dialogVisible.value = true
        } catch (error) {
            ElMessage.error('获取详情失败' + error)
        } finally {
            listRef.value.setLoading(false)
        }
    }

    // ========== 角色操作 - 失效 ==========
    // 失效角色（确认弹窗+接口调用）
    const handleDelete = async () => {
        if (!selectedRow.value) {
            ElMessage.warning('请先选中一条角色数据！')
            return
        }
        // 校验角色当前状态（已失效则提示）
        if (selectedRow.value.isDeleted === '1') {
            ElMessage.warning('该用户已处于失效状态！')
            return
        }

        try {
            // 确认弹窗
            await ElMessageBox.confirm(
                '确定要失效该用户吗？',
                '失效确认',
                { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
            )

            listRef.value.setLoading(true)
            // 调用失效接口
            const res = await request.post('/user/delUser', { userId: selectedRow.value.userId })
            if (res.code === 200) {
                ElMessage.success('失效成功')
                // 刷新列表
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            } else {
                ElMessage.error('失效失败：' + (res.msg || '接口异常'))
            }
        } catch (error) {
            // 排除取消弹窗的异常
            if (error !== 'cancel') {
                ElMessage.error('失效失败：网络异常')
            }
        } finally {
            listRef.value.setLoading(false)
        }
    }

    // 加载公司类型枚举
    const loadCompanyTypes = async () => {
        try {
            companyTypeList.value = await enumSelect('enumType', 'company_type')
        } catch (err) {
            console.error('获取公司类型枚举失败', err)
        }
    }

    // 根据公司类型code获取名称
    const getCompanyTypeName = (code) => {
        if (!code) return ''
        const type = companyTypeList.value.find(item => item.code === code)
        return type ? type.enumCodeName : code
    }

    // ========== 公司操作 ==========
    // 添加公司
    const handleAddCompany = () => {
        companyDialogTitle.value = '添加公司'
        Object.assign(companyForm, {
            companyId: '',
            companyName: '',
            companyType: '',
            contactPhone: '',
            companyAddress: '',
            isMain: '0',
            miniProgramCode: ''
        })
        editingCompanyIndex.value = -1
        loadCompanyTypes()
        showCompanyDialog.value = true
    }
    
    // 编辑公司
    const handleEditCompany = (row, index) => {
        companyDialogTitle.value = '编辑公司'
        Object.assign(companyForm, {
            companyId: row.companyId,
            companyName: row.companyName,
            companyType: row.companyType || '',
            contactPhone: row.contactPhone,
            companyAddress: row.companyAddress,
            isMain: row.isMain,
            miniProgramCode: row.miniProgramCode || ''
        })
        editingCompanyIndex.value = index
        loadCompanyTypes()
        showCompanyDialog.value = true
    }
    
    // 保存公司
    const handleSaveCompany = async () => {
        if (!companyFormRef.value) return
        
        const isValid = await new Promise((resolve) => {
            companyFormRef.value.validate((valid) => {
                resolve(valid);
            });
        });
        if (!isValid) return;
        
        // 如果是主公司，需要把其他公司设为非主公司
        if (companyForm.isMain === '1') {
            formData.companyList.forEach((item, idx) => {
                if (idx !== editingCompanyIndex.value) {
                    item.isMain = '0'
                }
            })
        }
        
        // 生成公司ID（如果没有）
        if (!companyForm.companyId) {
            companyForm.companyId = 'CP' + Date.now()
        }
        
        if (editingCompanyIndex.value === -1) {
            // 添加
            formData.companyList.push({ ...companyForm })
        } else {
            // 修改
            formData.companyList[editingCompanyIndex.value] = { ...companyForm }
        }
        
        showCompanyDialog.value = false
        ElMessage.success('保存成功')
    }
    
    // 删除公司
    const handleDeleteCompany = (index) => {
        ElMessageBox.confirm(
            '确定要删除该公司吗？',
            '删除确认',
            { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
        ).then(() => {
            formData.companyList.splice(index, 1)
            ElMessage.success('删除成功')
        }).catch(() => {})
    }

    // ========== 表单操作 - 提交/重置 ==========
    // 提交新增/编辑表单（校验+接口调用）
    const handleSubmit = async () => {
        if (!formRef.value) return

        // 表单校验（返回布尔值）
        const isValid = await new Promise((resolve) => {
            formRef.value.validate((valid) => {
                resolve(valid);
            });
        });
        if (!isValid) return;

        listRef.value.setLoading(true)
        try {
            // 调用保存/更新接口
            const res = await request.post('/user/saveOrUpdateUser', { ...formData, dialogType: dialogType.value })
            if (res.code === 200) {
                ElMessage.success(res.msg)
                dialogVisible.value = false // 关闭弹窗
                // 刷新列表
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            } else {
                const tip = dialogType.value === 'add' ? '新增失败' : '修改失败'
                ElMessage.error(tip + '：' + (res.msg || '接口异常'))
            }
        } catch (error) {
            ElMessage.error('接口异常:' + error)
        } finally {
            listRef.value.setLoading(false)
        }
    }

    // 重置搜索表单
    const handleReset = () => {
        Object.keys(searchForm).forEach((key) => {
            searchForm[key] = Array.isArray(searchForm[key]) ? [] : ''
        })
    }


    // ========== 菜单配置 - 弹窗操作 ==========
    // 打开菜单配置弹窗（加载角色关联菜单）
    const configuration = async (row) => {
        if (!row.userId) {
            ElMessage.error('参数为空无法配置');
            return
        }
        try {
            listRef.value.setLoading(true)
            // 查询角色关联菜单
            const res = await request.get('/user/getUserRoleTree', { params: { userId: row.userId } })
            if (res.code === 200) {
                // 1. 赋值角色列表数据
                roleTreeData.value = res.data || [];
                // 2. 提取 checkType=0的roleId 标记选中
                const roleList = Array.isArray(res.data) ? res.data : [];
                checkedRoleKeys.value = roleList
                    .filter(item => item.checkType === 0)  // checkType=0 选中
                    .map(item => item.roleId)             // 提取roleId
                    .filter(roleId => roleId);            // 过滤空值
                // 3. 打开弹窗
                configRoleDialogVisible.value = true;
                // 4.等待DOM渲染后设置选中状态
                await nextTick();
                if (roleTreeRef.value) {
                    roleTreeRef.value.userId = row.userId;
                    roleTreeRef.value.setCheckedKeys(checkedRoleKeys.value);
                }
            } else {
                ElMessage.error(res.msg || '查询失败')
            }
        } catch (error) {
            ElMessage.error('接口异常:' + error)
        } finally {
            listRef.value.setLoading(false)
        }
    }


    // 提交菜单配置（保存角色-菜单关联关系）
    const roleDialogSubmit = async () => {
        // 通过树组件获取选中的角色ID（包含半选和全选，根据业务需求调整）
        if (!roleTreeRef.value) {
            ElMessage.warning('角色树组件未初始化');
            return;
        }
        // 获取全选的节点key（roleId）
        const checkedRoleIds = roleTreeRef.value.getCheckedKeys()
        if (!checkedRoleIds.length) {
            ElMessage.warning('请先选择角色');
            return;
        }

        try {
            // 调用保存权限菜单配置
            const res = await request.post('/user/saveOrUpdateUserRole', {
                userId: roleTreeRef.value.userId, // 当前配置的用户ID
                roleList: checkedRoleIds // 选中的角色ID列表
            });
            if (res.code === 200) {
                ElMessage.success('角色配置成功');
                configRoleDialogVisible.value = false;
                // 刷新列表
                const pagination = listRef.value.getPagination();
                handleLoadList(pagination);
            } else {
                ElMessage.error('角色配置失败：' + (res.msg || '接口异常'));
            }
        } catch (error) {
            ElMessage.error('接口异常:' + error);
        }
    }

    // ========== 生命周期 ==========
    // 挂载时加载列表
    onMounted(async () => {
        await nextTick()
        setTimeout(() => {
            if (listRef.value?.isInited) {
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            }
        }, 50)
    })
    // 激活时刷新列表（keep-alive场景）
    onActivated(() => {
        if (listRef.value?.isInited) {
            const pagination = listRef.value.getPagination()
            handleLoadList(pagination)
        }
    })

    // ========== 暴露变量/方法 ==========
    return {
        // 响应式数据
        searchForm,
        listRef,
        dialogVisible,
        dialogType,
        formRef,
        selectedRow,
        formData,
        formRules,
        // 图标
        Plus, Edit, Delete,
        // 列表交互
        handleSelectionChange,
        handleCurrentRowChange,
        // 角色操作
        handleAdd,
        handleEdit,
        handleDelete,
        handleSubmit,
        handleLoadList,
        handleReset,
        // 菜单配置
        configuration,
        configRoleDialogVisible,
        roleTreeData,
        treeProps,
        roleDialogSubmit,
        checkedRoleKeys,
        // 公司相关
        showCompanyDialog,
        companyDialogTitle,
        companyFormRef,
        companyForm,
        companyFormRules,
        companyTypeList,
        getCompanyTypeName,
        handleAddCompany,
        handleEditCompany,
        handleSaveCompany,
        handleDeleteCompany
    }
}